interface OrderModalProps {
  order: PendingOrder;
  onClose: () => void;
  onDone: (order: PendingOrder, pricedItems: OrderItem[], total: number, paymentReceived: boolean) => void;
  onReject: (order: PendingOrder) => void;
  onUpdateStatus: (orderId: string, status: 'pending' | 'accepted' | 'rejected' | 'ready') => Promise<void>;
}

export default function OrderModal({ order, onClose, onDone, onReject, onUpdateStatus }: OrderModalProps) {
  const { hasFeature } = useSubscription();
  const customerName = (order as any).decryptedName || 'Customer';
  const orderStatus = order.status || 'pending';
  const customerAddress = (order as any).decryptedAddress || 'Address';
  const { announceOrder: voiceAnnounce } = useVoice();
  // Local copy of items with prices
  const [pricedItems, setPricedItems] = useState<OrderItem[]>(
    order.items.map((i) => ({ ...i, price: i.price ?? 0 }))
  );
  const [paymentReceived, setPaymentReceived] = useState(order.paymentReceived || false);
  const [processing, setProcessing] = useState(false);
  const [isRevealed, setIsRevealed] = useState(false);
  const { t, language } = useLanguage();
  useAntiCapture(true);

  // Security Checks
  const isPurged = customerName.includes('AUTO_PURGED');

  const handleReveal = () => {
    if (isPurged) {
      toast.error(language === 'hi' ? 'Purana data delete ho chuka hai!' : 'Old data has been purged!');
      return;
    }
    toast.warning(language === 'hi'
      ? 'Security Alert: Aap grahak ka data dekh rahe hain. Ye action record ho raha hai!'
      : 'Security Alert: You are viewing personal data. This action is being monitored!', {
      duration: 5000,
      icon: <ShieldAlert className="text-red-500" />
    });
    setIsRevealed(true);
  };

  const handleWhatsApp = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!isRevealed) {
      toast.info(language === 'hi' ? 'Pehle "Unlock" button dabayein' : 'Please click "Unlock" first');
      return;
    }

    if (isPurged || !order.customerPhone) return;

    const message = language === 'hi'
      ? `αñ¿αñ«αñ╕αÑìαññαÑç ${customerName}, αñåαñ¬αñòαñ╛ Order-Do αñ╕αÑç αñòαñ┐αñ»αñ╛ αñùαñ»αñ╛ αñæαñ░αÑìαñíαñ░ αññαÑêαñ»αñ╛αñ░ αñ╣αÑê! αñòαñ▓αÑçαñòαÑìαñƒ αñòαñ░ αñ▓αÑçαñéαÑñ αñòαÑüαñ▓: Γé╣${total.toFixed(0)}`
      : `Hello ${customerName}, your order from Order-Do is ready for pickup! Total: Γé╣${total.toFixed(0)}`;

    // Blind Redirect: Generator link only at the point of action
    const url = `https://wa.me/91${order.customerPhone}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
  };

  const maskPhone = (phone?: string) => {
    if (!phone) return '';
    if (phone.length < 5) return phone;
    return `${phone.slice(0, 2)}XXXXXX${phone.slice(-2)}`;
  };

  const total = useMemo(
    () => pricedItems.reduce((sum, i) => sum + (i.price || 0), 0),
    [pricedItems]
  );

  const updatePrice = (idx: number, price: number) => {
    setPricedItems((prev) =>
      prev.map((item, i) => (i === idx ? { ...item, price } : item))
    );
  };

  const handleDone = async () => {
    setProcessing(true);
    await onDone(order, pricedItems, total, paymentReceived);
    setProcessing(false);
  };

  const handleReject = async () => {
    setProcessing(true);
    await onReject(order);
    setProcessing(false);
  };

