import React, { createContext, useContext, useEffect, useState } from 'react';
import type { User, Session } from '@supabase/supabase-js';
import { supabase } from '../lib/supabase';
import { toast } from 'sonner';

interface AuthContextType {
  user: User | null;
  session: Session | null;
  loading: boolean;
  isAdmin: boolean;
  isAdminVerified: boolean;
  verifyAdminPin: (pin: string) => Promise<boolean>;
  logout: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType>({
  user: null,
  session: null,
  loading: true,
  isAdmin: false,
  isAdminVerified: false,
  verifyAdminPin: async () => false,
  logout: async () => {},
});

export const AuthProvider = ({ children }: { children: React.ReactNode }) => {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);
  const [isAdmin, setIsAdmin] = useState(false);
  const [isAdminVerified, setIsAdminVerified] = useState(false);

  const checkAdminStatus = async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('shops_profile')
        .select('role')
        .eq('id', userId)
        .single();

      if (error) {
        if (error.code !== 'PGRST116') console.warn('[Auth] Role fetch error:', error);
        return false;
      }
      return data?.role === 'admin';
    } catch (err) {
      return false;
    }
  };

  useEffect(() => {
    const initializeAuth = async () => {
      try {
        console.log('[Auth] System initialization...');
        const { data: { session: initialSession }, error } = await supabase.auth.getSession();

        if (error) {
          console.error('[Auth] Session initialization error:', error);
          // Standard Supabase behavior: Invalid sessions are treated as logged-out
          setLoading(false);
          return;
        }

        setSession(initialSession);
        const currentUser = initialSession?.user ?? null;
        setUser(currentUser);

        if (currentUser) {
          const isAdm = await checkAdminStatus(currentUser.id);
          setIsAdmin(isAdm);
        } else {
          setIsAdmin(false);
        }
      } catch (err) {
        console.error('[Auth] Critical initialization failure:', err);
      } finally {
        setLoading(false);
      }
    };

    initializeAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      async (_event, newSession) => {
        console.log(`[Auth] State Change Detected: ${_event}`);

        const currentUser = newSession?.user ?? null;

        if (_event === 'SIGNED_IN') {
          setLoading(true);
        }

        try {
          setSession(newSession);
          setUser(currentUser);

          if (currentUser) {
            const isAdm = await checkAdminStatus(currentUser.id);
            setIsAdmin(isAdm);
          } else {
            setIsAdmin(false);
            setIsAdminVerified(false);
          }

          if (_event === 'SIGNED_OUT') {
            setIsAdminVerified(false);
            localStorage.clear(); // Nuclear clear on signout to prevent stale port-drift
            sessionStorage.clear();
          }
        } catch (err) {
          console.error('[Auth] Event processing failed:', err);
        } finally {
          setLoading(false);
        }
      }
    );

    return () => subscription.unsubscribe();
  }, []);

  const verifyAdminPin = async (pin: string) => {
    if (!isAdmin) return false;

    try {
      // SECURE: PIN is verified on the server via RPC
      // The client never sees the hash or the comparison logic.
      const { data, error } = await supabase.rpc('verify_admin_pin', { 
        input_pin: pin 
      });

      if (error) {
        console.error('[Auth] PIN Verification Error:', error);
        toast.error('Security Protocol Failure: Verification rejected.');
        return false;
      }

      if (data === true) {
        setIsAdminVerified(true);
        return true;
      }

      return false;
    } catch (err) {
      console.error('[Auth] PIN error:', err);
      return false;
    }
  };

  const logout = async () => {
    setIsAdminVerified(false);

    // TC-003 FIX: Explicitly remove device session on logout to prevent "ghost devices"
    try {
      const { getDeviceId } = await import('../utils/deviceInfo');
      const deviceId = getDeviceId();
      if (user) {
        await supabase
          .from('user_sessions')
          .delete()
          .eq('user_id', user.id)
          .eq('device_id', deviceId);
      }
    } catch (err) {
      console.warn('[Auth] Session cleanup failed during logout:', err);
    }

    await supabase.auth.signOut();
  };

  return (
    <AuthContext.Provider value={{ user, session, loading, isAdmin, isAdminVerified, verifyAdminPin, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);

import React, { createContext, useContext, useState, useEffect } from 'react';
import { translations, type Language } from '../utils/translations';

interface LanguageContextType {
  language: Language;
  setLanguage: (lang: Language) => void;
  t: (path: string) => string;
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

export const LanguageProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [language, setLanguageState] = useState<Language>(() => {
    return (localStorage.getItem('order-do-lang') as Language) || 'hi';
  });

  useEffect(() => {
    localStorage.setItem('order-do-lang', language);
    // Setting document lang for accessibility
    document.documentElement.lang = language === 'hi' ? 'hi' : 'en';
  }, [language]);

  const t = (path: string): string => {
    const keys = path.split('.');
    let current: any = translations[language];

    for (const key of keys) {
      if (current && typeof current === 'object' && key in current) {
        current = current[key];
      } else {
        console.warn(`[i18n] Key not found: ${path}`);
        return path;
      }
    }

    return typeof current === 'string' ? current : path;
  };

  const setLanguage = (lang: Language) => setLanguageState(lang);

  return (
    <LanguageContext.Provider value={{ language, setLanguage, t }}>
      {children}
    </LanguageContext.Provider>
  );
};

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (context === undefined) {
    throw new Error('useLanguage must be used within a LanguageProvider');
  }
  return context;
};

import React, { createContext, useContext, useEffect, useState, useRef } from 'react';
import { supabase } from '../lib/supabase';
import { useAuth } from './AuthContext';
import { isExpired } from '../utils/dateUtils';

interface Subscription {
  status: 'active' | 'expired' | 'pending';
  expiry_date: string | null;
  confirmed_at: string | null;
  plan: {
    id: number;
    name: string;
    features: Record<string, boolean>;
  };
}

interface SubscriptionContextType {
  subscription: Subscription | null;
  loading: boolean;
  globalFree: boolean;
  hasFeature: (featureId: string) => boolean;
  refreshSubscription: () => Promise<void>;
}

const SubscriptionContext = createContext<SubscriptionContextType>({
  subscription: null,
  loading: true,
  globalFree: false,
  hasFeature: () => false,
  refreshSubscription: async () => {},
});

export const SubscriptionProvider = ({ children }: { children: React.ReactNode }) => {
  const { user, isAdmin } = useAuth();
  const [subscription, setSubscription] = useState<Subscription | null>(null);
  const [loading, setLoading] = useState(true);
  const [globalFree, setGlobalFree] = useState(false);
  const subscriptionRef = useRef<Subscription | null>(null);

  const fetchSubscription = async () => {
    if (!user) {
      setSubscription(null);
      setLoading(false);
      return;
    }

    try {
      // 1. Validate UUID format to prevent database crash
      const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
      if (!uuidRegex.test(user.id)) {
        setSubscription(null);
        setLoading(false);
        return;
      }

      // 2. Fetch Global Settings
      const { data: settings } = await supabase
        .from('admin_settings')
        .select('value')
        .eq('key', 'global_free_toggle')
        .maybeSingle();

      setGlobalFree(settings?.value === true || settings?.value === 'true');

      // 3. Fetch Shop Subscription and Server Time
      const [subResult, timeResult] = await Promise.all([
        supabase
          .from('subscriptions')
          .select(`
            status,
            expiry_date,
            plan:plans ( id, name, features )
          `)
          .eq('shop_id', user.id)
          .maybeSingle(),
        supabase.rpc('get_server_time')
      ]);

      const subData = subResult.data;
      const serverNow = timeResult.data ? new Date(timeResult.data) : new Date();

      if (subData && (subData.status === 'active' || subData.status === 'expired')) {
        // Double check status based on server time
        const actualStatus = (subData.status === 'active' && isExpired(subData.expiry_date, serverNow)) 
          ? 'expired' 
          : subData.status;

        setSubscription({ ...subData, status: actualStatus } as any);
      } else {
        // Check for a pending payment request to show "Selected Plan"
        const { data: pendingPayment } = await supabase
          .from('payments')
          .select('plan:plans(id, name, features)')
          .eq('shop_id', user.id)
          .eq('status', 'pending')
          .order('created_at', { ascending: false })
          .limit(1)
          .maybeSingle();

        if (pendingPayment) {
          setSubscription({
            status: 'pending',
            expiry_date: null,
            confirmed_at: null,
            plan: pendingPayment.plan as any
          });
        } else {
          setSubscription(subData as any || null);
        }
      }

      // 4. Fetch Activation Timestamp for active subscriptions from payment_history
      if (subData && subData.status === 'active') {
        const { data: activatedRecord } = await supabase
          .from('payment_history')
          .select('confirmed_at')
          .eq('shop_id', user.id)
          .eq('status', 'confirmed')
          .order('confirmed_at', { ascending: false })
          .limit(1)
          .maybeSingle();

        if (activatedRecord) {
          setSubscription(prev => prev ? { ...prev, confirmed_at: activatedRecord.confirmed_at } : null);
        }
      }
    } catch (err) {
      console.error('Error fetching subscription:', err);
    } finally {
      setLoading(false);
    }
  };

  // TC-015: Keep ref in sync with state for heartbeat access
  useEffect(() => {
    subscriptionRef.current = subscription;
  }, [subscription]);

  useEffect(() => {
    fetchSubscription();

    if (!user) return;

    // TC-015 FIX: Heartbeat uses ref to avoid stale closure
    // Always re-fetch from server to get fresh expiry state
    const heartbeat = setInterval(() => {
      const current = subscriptionRef.current;
      if (current?.expiry_date && isExpired(current.expiry_date)) {
        console.log('[SubscriptionContext] Heartbeat detected expiration');
        fetchSubscription(); // Refresh state to lock UI
      }
    }, 60000);

    // Listen for realtime updates to this shop's subscription or payments
    const channel = supabase.channel(`shop-sub-${user.id}`)
      .on('postgres_changes', { 
        event: '*', 
        schema: 'public', 
        table: 'subscriptions',
        filter: `shop_id=eq.${user.id}`
      }, () => {
        console.log('[SubscriptionContext] Realtime Update detected (subscriptions)');
        fetchSubscription();
      })
      .on('postgres_changes', { 
        event: '*', 
        schema: 'public', 
        table: 'payment_history',
        filter: `shop_id=eq.${user.id}`
      }, () => {
        console.log('[SubscriptionContext] Realtime Update detected (payment_history)');
        fetchSubscription();
      })
      .on('postgres_changes', { 
        event: '*', 
        schema: 'public', 
        table: 'payments',
        filter: `shop_id=eq.${user.id}`
      }, () => {
        console.log('[SubscriptionContext] Realtime Update detected (payments pool)');
        fetchSubscription();
      })
      .subscribe();

    return () => {
      clearInterval(heartbeat);
      supabase.removeChannel(channel);
    };
  }, [user]);

  const hasFeature = (featureId: string) => {
    // Admin always has all features
    if (isAdmin) return true;

    // Global Free Toggle
    if (globalFree) return true;

    // Check Subscription
    if (!subscription || subscription.status !== 'active') return false;

    // Check if expiry date has passed
    if (isExpired(subscription.expiry_date)) {
      return false;
    }

    // Check plan features
    return subscription.plan.features[featureId] === true;
  };

  return (
    <SubscriptionContext.Provider value={{ 
      subscription, 
      loading, 
      globalFree,
      hasFeature, 
      refreshSubscription: fetchSubscription 
    }}>
      {children}
    </SubscriptionContext.Provider>
  );
};

export const useSubscription = () => useContext(SubscriptionContext);

import React, { createContext, useContext, useState, useCallback } from 'react';
import { useLanguage } from './LanguageContext';

export type CharacterAction = 'idle' | 'talking' | 'waving' | 'pointing' | 'blinking' | 'thinking' | 'explaining' | 'success';

interface TalkingCharacterContextType {
  isSpeaking: boolean;
  speak: (text: string, action?: CharacterAction) => void;
  stop: () => void;
  repeat: () => void;
  action: CharacterAction;
  setAction: (action: CharacterAction) => void;
  isVisible: boolean;
  setIsVisible: (visible: boolean) => void;
  isMuted: boolean;
  toggleMute: () => void;
  currentText: string;
}

const TalkingCharacterContext = createContext<TalkingCharacterContextType | undefined>(undefined);

export function TalkingCharacterProvider({ children }: { children: React.ReactNode }) {
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [action, setAction] = useState<CharacterAction>('idle');
  const [isVisible, setIsVisible] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [currentText, setCurrentText] = useState('');
  const [lastText, setLastText] = useState('');
  const { language } = useLanguage();

  const toggleMute = () => setIsMuted(prev => !prev);

  const speak = useCallback((text: string, customAction: CharacterAction = 'talking') => {
    if (isMuted) return;

    setLastText(text);
    setCurrentText(text);
    window.speechSynthesis.cancel();

    const utterance = new SpeechSynthesisUtterance(text);

    // Voice selection logic - Search for "Crystal Clear" High-Quality Female Voices
    const voices = window.speechSynthesis.getVoices();

    const findClearVoice = (langCode: string, preferences: string[]) => {
        const langVoices = voices.filter(v => v.lang.includes(langCode));
        for (const pref of preferences) {
            const found = langVoices.find(v => v.name.includes(pref));
            if (found) return found;
        }
        return langVoices.find(v => v.name.toLowerCase().includes('female') || v.name.toLowerCase().includes('google') || v.name.toLowerCase().includes('microsoft'));
    };

    const hiVoice = findClearVoice('hi-IN', ['Google αñ╣αñ┐αñ¿αÑìαñªαÑÇ', 'Heera', 'Kalpana']);
    const enVoice = findClearVoice('en-', ['Google UK English Female', 'Zira', 'Samantha', 'Google US English']);

    if (language === 'hi' && hiVoice) {
      utterance.voice = hiVoice;
    } else if (enVoice) {
      utterance.voice = enVoice;
    }

    utterance.pitch = 1.1; 
    utterance.rate = 0.95;  
    utterance.volume = 1.0;

    utterance.onstart = () => {
      setIsSpeaking(true);
      setAction(customAction);
      setIsVisible(true);
    };

    utterance.onend = () => {
      setIsSpeaking(false);
      setAction('idle');
      setTimeout(() => {
        if (!window.speechSynthesis.speaking) {
          setCurrentText('');
        }
      }, 2000);
    };

    utterance.onerror = () => {
      setIsSpeaking(false);
      setAction('idle');
      setCurrentText('');
    };

    window.speechSynthesis.speak(utterance);
  }, [isMuted, language]);

  const repeat = useCallback(() => {
    if (lastText) {
      speak(lastText);
    }
  }, [lastText, speak]);

  const stop = useCallback(() => {
    window.speechSynthesis.cancel();
    setIsSpeaking(false);
    setAction('idle');
    setCurrentText('');
  }, []);

  return (
    <TalkingCharacterContext.Provider 
      value={{ 
        isSpeaking, 
        speak, 
        stop, 
        repeat,
        action, 
        setAction, 
        isVisible, 
        setIsVisible,
        isMuted,
        toggleMute,
        currentText
      }}
    >
      {children}
    </TalkingCharacterContext.Provider>
  );
}

export function useTalkingCharacter() {
  const context = useContext(TalkingCharacterContext);
  if (context === undefined) {
    throw new Error('useTalkingCharacter must be used within a TalkingCharacterProvider');
  }
  return context;
}

import React, { createContext, useContext, useEffect, useState } from 'react';

type Theme = 'light' | 'dark';

interface ThemeContextType {
  theme: Theme;
  toggleTheme: () => void;
  setTheme: (theme: Theme) => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [theme, setThemeState] = useState<Theme>(() => {
    // 1. Check localStorage
    const stored = localStorage.getItem('order-do-theme') as Theme | null;
    if (stored) return stored;

    // 2. Check system preference
    if (window.matchMedia('(prefers-color-scheme: dark)').matches) return 'dark';

    return 'light';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('order-do-theme', theme);
  }, [theme]);

  // Listen for system theme changes if no manual toggle has occurred
  useEffect(() => {
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    const handleChange = (e: MediaQueryListEvent) => {
      const hasManualToggle = localStorage.getItem('order-do-theme');
      if (!hasManualToggle) {
        setThemeState(e.matches ? 'dark' : 'light');
      }
    };

    mediaQuery.addEventListener('change', handleChange);
    return () => mediaQuery.removeEventListener('change', handleChange);
  }, []);

  const toggleTheme = () => {
    setThemeState((prev) => (prev === 'light' ? 'dark' : 'light'));
  };

  const setTheme = (t: Theme) => setThemeState(t);

  const value: ThemeContextType = {
    theme,
    toggleTheme,
    setTheme,
  };

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};

