        admin_id: adminUser.id,
        amount: confirmForm.amount,
        payment_method: confirmForm.method,
        utr_number: confirmForm.utr,
        duration_days: daysToAdd,
        confirmed_at: now.toISOString(),
        status: 'confirmed',
        plan_id: confirmingPayment.plan_id
