      if (histErr) throw histErr;

      if (!confirmingPayment.id.startsWith('manual-')) {
        await supabase.from('payments').update({ 
          status: 'confirmed', 
          confirmed_at: now.toISOString() 
        }).eq('id', confirmingPayment.id);
